{% block title %}Homepage Editor{% endblock %}
{% block nav_homepage %}active{% endblock %}
{% block page_title %}Homepage Editor{% endblock %}

{% block extra_styles %}
/* ── SHELL ── */
.editor-shell { display:grid; grid-template-columns:200px 1fr 300px; height:calc(100vh - 60px); margin:-28px; overflow:hidden; }

/* ── LEFT ── */
.ep-left { background:var(--surface); border-right:1px solid var(--border); overflow-y:auto; }
.ep-left-title { padding:16px 16px 8px; font-size:10px; font-weight:700; letter-spacing:.1em; text-transform:uppercase; color:var(--text-muted); }
.ep-row { display:flex; align-items:center; gap:10px; padding:10px 16px; cursor:pointer; border-left:3px solid transparent; transition:all .12s; }
.ep-row:hover { background:var(--base); }
.ep-row.active { background:var(--navy-light); border-left-color:var(--navy); }
.ep-row-label { font-size:13px; font-weight:500; color:var(--text); }

/* ── MIDDLE ── */
.ep-mid { background:#e8e8e8; overflow-y:auto; padding:20px; display:flex; flex-direction:column; gap:16px; }
.ep-preview-card { border-radius:10px; overflow:hidden; border:3px solid transparent; cursor:pointer; transition:border-color .15s; box-shadow:0 2px 12px rgba(0,0,0,.12); }
.ep-preview-card:hover { border-color:#9aa5b8; }
.ep-preview-card.active { border-color:var(--navy); box-shadow:0 0 0 1px var(--navy),0 4px 16px rgba(27,42,74,.2); }
.ep-preview-label { display:flex; align-items:center; justify-content:space-between; padding:10px 14px; background:#fff; border-top:1px solid #e5e2dc; }
.ep-preview-name { font-size:12px; font-weight:700; color:#1a1a1a; }
.ep-preview-desc { font-size:10px; color:#9a9a9a; margin-top:1px; }
.ep-check { background:var(--navy); color:#fff; border-radius:50%; width:18px; height:18px; font-size:9px; font-weight:700; display:flex; align-items:center; justify-content:center; flex-shrink:0; }

/* ── PREVIEW VIEWPORT — scaled hero ── */
.ep-viewport { width:100%; overflow:hidden; position:relative; background:var(--navy); }
.ep-viewport-inner { width:1280px; transform-origin:top left; }

/* ── REAL HERO CSS (copied from storefront) ── */
.pv-hero { position:relative; overflow:hidden; background:var(--navy); display:flex; align-items:center; --navy:#1B2A4A; --navy-hover:#243660; --gold:#C9A84C; --emerald:#1A5C45; --surface:#fff; --r-btn:8px; }
.pv-hero-bg { position:absolute; inset:0; background:linear-gradient(135deg,#1B2A4A 0%,#0D1829 50%,#1A3A2A 100%); }
.pv-hero-pattern { position:absolute; inset:0; opacity:.04; background-image:radial-gradient(circle,#fff 1px,transparent 1px); background-size:32px 32px; }
.pv-hero-glow { position:absolute; right:15%; top:10%; width:500px; height:500px; background:radial-gradient(ellipse,rgba(201,168,76,.12) 0%,transparent 70%); pointer-events:none; }
.pv-hero-content { position:relative; z-index:2; max-width:1280px; margin:0 auto; padding:80px 32px; display:flex; align-items:center; justify-content:space-between; gap:48px; width:100%; }
.pv-hero-text { max-width:560px; }
.pv-overline { display:inline-flex; align-items:center; gap:8px; font-size:11px; font-weight:600; letter-spacing:.12em; text-transform:uppercase; color:#C9A84C; margin-bottom:20px; }
.pv-overline::before { content:''; display:block; width:24px; height:1px; background:#C9A84C; }
.pv-h1 { font-family:'Cormorant Garamond',serif; font-size:60px; line-height:1.08; color:#fff; margin-bottom:20px; letter-spacing:-.5px; word-wrap:break-word; overflow-wrap:break-word; width:100%; }
.pv-sub { font-size:17px; font-weight:300; line-height:1.65; color:rgba(255,255,255,.72); margin-bottom:36px; width:100%; }
.pv-actions { display:flex; gap:14px; align-items:center; }
.pv-actions--centred { justify-content:center; }
.pv-btn-primary { padding:14px 28px; background:#fff; color:#1B2A4A; border:none; border-radius:8px; font-family:'DM Sans',sans-serif; font-size:15px; font-weight:700; display:inline-flex; align-items:center; gap:8px; text-decoration:none; cursor:pointer; }
.pv-btn-secondary { padding:14px 28px; background:transparent; color:#fff; border:1.5px solid rgba(255,255,255,.4); border-radius:8px; font-family:'DM Sans',sans-serif; font-size:15px; font-weight:600; display:inline-flex; align-items:center; gap:8px; text-decoration:none; cursor:pointer; }
.pv-btn-outline { padding:14px 28px; background:transparent; color:#fff; border:1.5px solid rgba(255,255,255,.4); border-radius:8px; font-family:'DM Sans',sans-serif; font-size:15px; font-weight:600; display:inline-flex; align-items:center; gap:8px; text-decoration:none; cursor:pointer; }
.pv-stats { display:flex; gap:32px; margin-top:40px; padding-top:32px; border-top:1px solid rgba(255,255,255,.1); }
.pv-stats--centred { justify-content:center; }
.pv-stat-num { font-family:'Cormorant Garamond',serif; font-size:28px; font-weight:700; color:#fff; line-height:1; }
.pv-stat-label { font-size:12px; color:rgba(255,255,255,.55); margin-top:3px; }
.pv-card { background:rgba(255,255,255,.07); backdrop-filter:blur(20px); border:1px solid rgba(255,255,255,.12); border-radius:12px; padding:16px; min-width:0; flex:1; }
.pv-cards-row { display:flex; flex-direction:row; gap:12px; flex-shrink:0; align-items:flex-start; max-width:420px; }
.pv-card-badge { display:inline-flex; align-items:center; gap:6px; background:#1A5C45; color:#fff; font-size:11px; font-weight:700; letter-spacing:.06em; padding:4px 10px; border-radius:4px; margin-bottom:16px; }
.pv-card-img { width:220px; height:180px; background:linear-gradient(135deg,rgba(255,255,255,.05),rgba(255,255,255,.01)); border-radius:10px; margin:0 auto 16px; display:flex; align-items:center; justify-content:center; font-size:80px; overflow:hidden; }
.pv-card-name { font-family:'Cormorant Garamond',serif; font-size:20px; font-weight:600; color:#fff; margin-bottom:4px; }
.pv-card-price { color:#C9A84C; font-weight:700; font-size:18px; }
.pv-card-old { color:rgba(255,255,255,.4); font-size:14px; text-decoration:line-through; margin-left:8px; }
/* reactive button classes */
.pv-btn { display:inline-flex;align-items:center;gap:8px;padding:14px 28px;border-radius:8px;font-family:'DM Sans',sans-serif;font-size:15px;font-weight:600;cursor:default; }
.pv-btn.filled.navy    { background:#1B2A4A;color:#fff; }

