{% with icon_bgs="#EEF1F8,#EAF3EE,#FDF5E6,#EEF1F8,#EAF3EE,#FDF5E6" %}
<div class="container">
    <div class="section-header">
    {% if cat_overline %}<div class="section-overline" style="color:var({{ cat_overline_colour }});">{{ cat_overline }}</div>{% endif %}
    <h2 class="section-title" style="color:var({{ cat_heading_colour }});font-size:{{ cat_heading_size }};">{{ cat_heading }}</h2>
  </div>
  <div class="cat-e-wrap">
    {% if featured_categories %}
      {% for cat in featured_categories %}
      {% if forloop.counter == 1 %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EEF1F8;">
      {% elif forloop.counter == 2 %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EAF3EE;">
      {% elif forloop.counter == 3 %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#FDF5E6;">
      {% elif forloop.counter == 4 %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EEF1F8;">
      {% elif forloop.counter == 5 %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EAF3EE;">
      {% else %}<a href="/categories/{{ cat.slug }}/" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#FDF5E6;">{% endif %}
          {% if cat.image %}<img src="{{ cat.image.url }}" alt="{{ cat.name }}">{% else %}🗂️{% endif %}
        </div><div class="cat-e-name">{{ cat.name }}</div></div>
        <div class="cat-e-right"><span class="cat-e-badge">{{ cat.product_count|default:0 }}</span><span class="cat-e-arrow">›</span></div>
      </a>
      {% endfor %}
    {% else %}
      <a href="#" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EEF1F8;">📱</div><div class="cat-e-name">Phones</div></div><div class="cat-e-right"><span class="cat-e-badge">—</span><span class="cat-e-arrow">›</span></div></a>
