      <a href="#" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EEF1F8;">🏠</div><div class="cat-e-name">Smart Home</div></div><div class="cat-e-right"><span class="cat-e-badge">—</span><span class="cat-e-arrow">›</span></div></a>
      <a href="#" class="cat-e-row"><div class="cat-e-left"><div class="cat-e-icon" style="background:#EAF3EE;">⌚</div><div class="cat-e-name">Wearables</div></div><div class="cat-e-right"><span class="cat-e-badge">—</span><span class="cat-e-arrow">›</span></div></a>
