{% extends "dashboard/base_dashboard.html" %}
{% load humanize %}

{% block title %}Categories — Dashboard{% endblock %}
{% block page_title %}Categories{% endblock %}
{% block nav_categories %}active{% endblock %}

{% block extra_styles %}
.table-wrap { background: var(--surface); border: 1px solid var(--border); border-radius: var(--r-lg); overflow: hidden; }
table { width: 100%; border-collapse: collapse; }
thead th { padding: 11px 16px; text-align: left; font-size: 11px; font-weight: 600; color: var(--text-muted); text-transform: uppercase; letter-spacing: .06em; background: var(--surface-alt); border-bottom: 1px solid var(--border); }
tbody tr { border-bottom: 1px solid var(--border); transition: background .12s; }
tbody tr:last-child { border-bottom: none; }
