/* ── CATEGORIES E — list with badges ── */
.cat-e-wrap { background:#fff; border:0.5px solid #E5E2DC; border-radius:10px; overflow:hidden; }
.cat-e-row { display:flex; align-items:center; justify-content:space-between; padding:12px 16px; border-bottom:0.5px solid #E5E2DC; text-decoration:none; transition:background .15s; }
.cat-e-row:last-child { border-bottom:none; }
