}
.btn-hero-primary:hover { background: var(--gold); color: white; transform: translateY(-1px); }
.btn-hero-secondary {
  padding: 14px 28px;
  background: transparent; color: white;
  border: 1.5px solid rgba(255,255,255,0.4);
  border-radius: var(--r-btn);
  font-family: 'DM Sans', sans-serif; font-size: 15px; font-weight: 600;
  cursor: pointer; transition: all 0.15s; text-decoration: none;
}
.btn-hero-secondary:hover { border-color: white; background: rgba(255,255,255,0.08); }
.hero-stats {
  display: flex; gap: 32px; margin-top: 40px;
  padding-top: 32px; border-top: 1px solid rgba(255,255,255,0.1);
}
.hero-stat-num {
  font-family: 'Cormorant Garamond', serif;
  font-size: 28px; font-weight: 700; color: white; line-height: 1;
}
.hero-stat-label { font-size: 12px; color: rgba(255,255,255,0.55); margin-top: 3px; }
.hero-card {
  background: rgba(255,255,255,0.07);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 16px; padding: 28px;
  min-width: 280px;
}
.hero-card-badge {
  display: inline-flex; align-items: center; gap: 6px;
  background: var(--emerald); color: white;
  font-size: 11px; font-weight: 700; letter-spacing: 0.06em;
  padding: 4px 10px; border-radius: 4px; margin-bottom: 16px;
}
.hero-card-img {
  width: 220px; height: 180px;
  background: linear-gradient(135deg, rgba(255,255,255,0.05), rgba(255,255,255,0.01));
  border-radius: 10px; margin: 0 auto 16px;
  display: flex; align-items: center; justify-content: center;
  font-size: 80px;
}
.hero-card-name {
  font-family: 'Cormorant Garamond', serif;
  font-size: 20px; font-weight: 600; color: white; margin-bottom: 4px;
}
.hero-card-price { color: var(--gold); font-weight: 700; font-size: 18px; }
.hero-card-old { color: rgba(255,255,255,0.4); font-size: 14px; text-decoration: line-through; margin-left: 8px; }
{% endblock %}

{% block content %}

{% for section in sections %}
  {# Hero gets its own class; newsletter keeps its legacy wrapper class #}
  {% if section.key == 'hero' %}
  <section id="section-{{ section.key }}" class="hero hp-section" style="{{ section.get_bg_style }} {{ section.get_css_vars }}">
  {% elif section.key == 'newsletter' %}
  <section id="section-{{ section.key }}" class="newsletter-section hp-section" style="{{ section.get_bg_style }} {{ section.get_spacing_padding }} {{ section.get_css_vars }}">
  {% else %}
  <section id="section-{{ section.key }}" class="section hp-section hp-section--{{ section.key }}" style="{{ section.get_bg_style }} {{ section.get_spacing_padding }} {{ section.get_css_vars }}">
  {% endif %}
    {% with partial="store/sections/"|add:section.key|add:"_v"|add:section.variant|add:".html" %}
      {% include partial %}
    {% endwith %}
  </section>
{% endfor %}

{% endblock %}

