calcScale() {
  const mid = this.$el.querySelector('.ep-mid');
  if (!mid) return;
  const availW = mid.clientWidth - 40; // padding
  this.scale = Math.min(availW / 1280, 1);
  // Inner height = hero min-height (100vh approx 700px for preview)
  this.vpInnerH = 700;
  this.vpH = Math.round(700 * this.scale);
},

selectVariant(v) {
  this.activeVariant = v;
},

v3BgStyle() {
  const v = this.v3;
  const imgUrl = v.bgImagePreview || (v.hasBgImage ? '{{ hero_section.bg_image.url|default:"" }}' : '');
  if (imgUrl) {
    const pct = v.bg_overlay_opacity;
    const col = v.bg_overlay_colour;
    return `background:linear-gradient(color-mix(in srgb,var(${col}) ${pct}%,transparent),color-mix(in srgb,var(${col}) ${pct}%,transparent)),url('${imgUrl}') center/cover no-repeat;`;
  }
  return '';
},

async saveAll() {
  this.saving = true;
  const csrf = document.cookie.match(/csrftoken=([^;]+)/)?.[1] || '';
  const av = this.av;
  try {
    // Save section layout/style for active variant
    const fd = new FormData();
    fd.append('variant', this.activeVariant);
    ['bg_mode','bg_colour','bg_overlay_colour','heading_colour','heading_size','heading_weight',
     'body_colour','body_size','btn1_enabled','btn1_style','btn1_colour',
     'btn2_enabled','btn2_style','btn2_colour'].forEach(k => fd.append(k, String(av[k])));
    fd.append('bg_overlay_opacity', String(av.bg_overlay_opacity));
    if (av.bgImageFile) fd.append('bg_image', av.bgImageFile);
    console.log('[editor] saving — bgImageFile:', !!av.bgImageFile, 'hasBgImage:', av.hasBgImage, 'bg_mode:', av.bg_mode);
    // Save selected deal product IDs and all variant states into custom_content
    const variantState = (v) => ({
      bg_mode: v.bg_mode, bg_colour: v.bg_colour,
      bg_overlay_colour: v.bg_overlay_colour, bg_overlay_opacity: v.bg_overlay_opacity,
      heading_colour: v.heading_colour, heading_size: v.heading_size, heading_weight: v.heading_weight,
      heading_bold: v.heading_bold, heading_italic: v.heading_italic, heading_underline: v.heading_underline,
      body_colour: v.body_colour, body_size: v.body_size,
      btn1_enabled: v.btn1_enabled, btn1_style: v.btn1_style, btn1_colour: v.btn1_colour,
      btn2_enabled: v.btn2_enabled, btn2_style: v.btn2_style, btn2_colour: v.btn2_colour,
      overline_colour: v.overline_colour, show_deal_card: v.hero_show_deal_card, show_stats: v.hero_show_stats,
      hasBgImage: v.hasBgImage || !!v.bgImageFile,
    });
    fd.append('custom_content', JSON.stringify({
      deal_product_ids: this.selectedDealIds.filter(id=>id),
      overline_colour: av.overline_colour,
      show_deal_card: av.hero_show_deal_card,
      show_stats: av.hero_show_stats,
      variants: { v1: variantState(this.v1), v2: variantState(this.v2), v3: variantState(this.v3) },
    }));

    const r1 = await fetch('/dashboard/homepage/section/{{ hero_section.pk }}/save/', {
      method:'POST', headers:{'X-CSRFToken':csrf}, body:fd
    });
    if ((await r1.json()).status !== 'ok') { this.toast('Style save failed'); return; }

    // Save hero content fields
    const fd2 = new FormData();
    ['hero_overline','hero_headline','hero_subheading',
     'hero_cta1_text','hero_cta1_link','hero_cta2_text','hero_cta2_link'].forEach(k => fd2.append(k, av[k]||''));
    const r2 = await fetch('/dashboard/settings/hero-content/', {
      method:'POST', headers:{'X-CSRFToken':csrf}, body:fd2
    });
    if ((await r2.json()).status !== 'ok') { this.toast('Content save failed'); return; }

    // If a bg image was uploaded, mark it as set and clear the file reference
    if (av.bgImageFile) { av.hasBgImage = true; av.bgImageFile = null; }
    this.toast('Saved ✓');
  } catch { this.toast('Network error'); }
  finally { this.saving = false; }
},

toast(msg) { this.toastMsg=msg; this.toastVisible=true; setTimeout(()=>this.toastVisible=false, 2800); },

