  const file = event.target.files[0];
  if (!file) return;

  const fd = new FormData();
  fd.append('image', file);
  const csrf = document.cookie.match(/csrftoken=([^;]+)/)?.[1] || '';

  try {
    const r = await fetch('/dashboard/upload-category-image/', {
      method: 'POST',
      headers: { 'X-CSRFToken': csrf },
      body: fd
    });

