{% load humanize %}
<div class="container">
  <div class="section-header" style="text-align:left;margin-bottom:32px;">
    {% if feat_overline %}<div class="section-overline" style="color:var({{ feat_overline_colour }});justify-content:flex-start;">{{ feat_overline }}</div>{% endif %}
    <h2 class="section-title" style="color:var({{ feat_heading_colour }});font-size:{{ feat_heading_size }};">{{ feat_heading }}</h2>
    {% if feat_subheading %}<p class="section-sub">{{ feat_subheading }}</p>{% endif %}
  </div>
  {% if feat_products %}
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start;">
    {# Hero card — first product #}
    {% with product=feat_products.0 %}
    <div>{% include "store/_product_card.html" %}</div>
    {% endwith %}
    {# 2×2 grid — remaining 4 #}
    <div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
        {% for product in feat_products|slice:"1:5" %}{% include "store/_product_card.html" %}{% endfor %}
      </div>
      {% if feat_view_all_link %}
      <div class="view-all-row">
        <a href="{{ feat_view_all_link }}" class="view-all-link">View All →</a>
      </div>
      {% endif %}
    </div>
  </div>
  {% endif %}
</div>

