setFeatHero(val) {
  const id = val ? parseInt(val) : null;
  const k = 'fv'+this.featVariant;
  const cur = this[k];
  if (id) {
    let ids = cur.product_ids.filter(x => x !== id);
    ids.unshift(id);
    if (ids.length > 5) ids = ids.slice(0, 5);
    this[k] = {...cur, hero_product_id: id, product_ids: ids};
  } else {
    this[k] = {...cur, hero_product_id: null};
  }
  console.log('[setFeatHero]', k, 'id:', id);
},

