{% load humanize %}
{% if deals %}
<div class="container">
  <div class="deals-header">
    <h2 class="deals-title" style="color:var(--section-heading-color);font-size:var(--section-heading-size);font-weight:var(--section-heading-weight);">{{ settings.section_heading_deals }}</h2>
  </div>
  <div class="product-grid">
    {% for product in deals %}
      <div class="deal-card">{% include "store/_product_card.html" %}</div>
    {% endfor %}
  </div>
  <div style="text-align:center;margin-top:36px;">
    <a href="/products/?sale=1" class="btn btn--{{ section.btn1_style }} btn--{{ section.btn1_colour|slice:'2:' }}">See All Deals →</a>
  </div>
</div>
{% endif %}

items.Text:
{% load humanize %}
{% if deals %}
<div class="container">
  <div class="deals-header">
    <h2 class="deals-title" style="color:var(--section-heading-color);font-size:var(--section-heading-size);font-weight:var(--section-heading-weight);">{{ settings.section_heading_deals }}</h2>
  </div>
  <div class="product-grid">
    {% for product in deals %}
      <div class="deal-card">{% include "store/_product_card.html" %}</div>
    {% endfor %}
  </div>
  <div style="text-align:center;margin-top:36px;">
    <a href="/products/?sale=1" class="btn btn--{{ section.btn1_style }} btn--{{ section.btn1_colour|slice:'2:' }}">See All Deals →</a>
  </div>
</div>
{% endif %}

input.newStr:
get afv() { return this['fv' + this.featVariant]; },
dealsVariant: '{{ deals_section.variant|default:"1" }}',
dealsProducts: {{ deals_products_json|safe }},
dealsSearch: '',
_dsv: {{ deals_saved_json|safe }},
dv1: {heading:"Today's Deals",heading_size:'38px',heading_colour:'--surface',view_all_link:'/products/?sale=1',view_all_colour:'--surface',product_ids:[]},
get adv() { return this['dv' + this.dealsVariant]; },
setDv(key, val) { const k='dv'+this.dealsVariant; this[k]={...this[k],[key]:val}; },
toggleDealProduct(pid) {
  const k='dv'+this.dealsVariant; const cur=this[k];
  const ids=cur.product_ids.includes(pid)?cur.product_ids.filter(id=>id!==pid):(cur.product_ids.length<8?[...cur.product_ids,pid]:cur.product_ids);
  this[k]={...cur,product_ids:ids};
},

