{% load humanize %}
{% if deals %}
<div x-data="dealCountdown('{{ deals_timer_end }}')" x-init="start()">

  {% if deals_timer_visible or deals_banner_label_visible %}
  <div style="background:var({{ deals_banner_bg }});padding:20px 0;text-align:center;margin-bottom:0;">
    <div class="container">
      {% if deals_banner_label_visible %}
      <div style="color:var({{ deals_banner_text }});font-size:{{ deals_banner_label_size }};font-weight:600;margin-bottom:8px;">{{ deals_banner_label }}</div>
      {% endif %}
      {% if deals_timer_visible %}
      <div x-show="!expired" style="display:flex;justify-content:center;gap:24px;">
        <div style="text-align:center;">
          <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;" x-text="days"></div>
          <div style="font-size:12px;color:var({{ deals_banner_text }});opacity:0.7;margin-top:4px;">days</div>
        </div>
        <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;align-self:flex-start;padding-top:4px;">:</div>
        <div style="text-align:center;">
          <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;" x-text="hours"></div>
          <div style="font-size:12px;color:var({{ deals_banner_text }});opacity:0.7;margin-top:4px;">hrs</div>
        </div>
        <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;align-self:flex-start;padding-top:4px;">:</div>
        <div style="text-align:center;">
          <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;" x-text="mins"></div>
          <div style="font-size:12px;color:var({{ deals_banner_text }});opacity:0.7;margin-top:4px;">mins</div>
        </div>
        <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;align-self:flex-start;padding-top:4px;">:</div>
        <div style="text-align:center;">
          <div style="font-family:'Cormorant Garamond',serif;font-weight:700;color:var({{ deals_banner_text }});font-size:{{ deals_timer_size }};line-height:1;" x-text="secs"></div>
          <div style="font-size:12px;color:var({{ deals_banner_text }});opacity:0.7;margin-top:4px;">secs</div>
        </div>
      </div>
      {% endif %}
    </div>
  </div>
  {% endif %}

  <div class="container" style="padding-top:48px;">
    <div class="deals-header">
      <div>
        <h2 class="deals-title" style="color:var({{ deals_heading_colour }});font-size:{{ deals_heading_size }};">{{ deals_heading }}</h2>
        {% if deals_subheading %}<p style="color:var({{ deals_subheading_colour }});font-size:{{ deals_subheading_size }};margin-top:8px;opacity:0.8;">{{ deals_subheading }}</p>{% endif %}
      </div>
    </div>
    <div class="product-grid">
      {% for product in deals %}
        <div class="deal-card">{% include "store/_product_card.html" %}</div>
      {% endfor %}
    </div>
    {% if deals_view_all_link %}
    <div style="text-align:center;margin-top:36px;">
      <a href="{{ deals_view_all_link }}" class="btn btn--outline btn--{{ deals_view_all_colour|slice:'2:' }}">See All Deals →</a>
    </div>
    {% endif %}
  </div>
</div>

<script>
function dealCountdown(endStr) {
  return {
    days:'00', hours:'00', mins:'00', secs:'00', expired:false, _t:null,
    start() {
      if (!endStr) { this.expired=true; return; }
      this._tick();
      this._t = setInterval(() => this._tick(), 1000);
    },
    _tick() {
      const diff = new Date(endStr) - new Date();
      if (diff <= 0) { this.expired=true; clearInterval(this._t); return; }
      const p = (n) => String(Math.floor(n)).padStart(2,'0');
      this.days  = p(diff/86400000);
      this.hours = p((diff%86400000)/3600000);
      this.mins  = p((diff%3600000)/60000);
      this.secs  = p((diff%60000)/1000);
    }
  };
}
</script>
{% endif %}

